{
  "name": "Watermark Remover AI",
  "description": "A free tool powered by Gemini Flash to intelligently remove watermarks from your images."
}

export interface ProcessedImageResult {
  originalUrl: string;
  processedUrl: string;
}

export interface LoadingState {
  status: 'idle' | 'uploading' | 'processing' | 'success' | 'error';
  message?: string;
}

export enum ImageMimeType {
  PNG = 'image/png',
  JPEG = 'image/jpeg',
  WEBP = 'image/webp',
  HEIC = 'image/heic',
  HEIF = 'image/heif',
}

import { GoogleGenAI } from "@google/genai";

// Initialize the client
// API Key is strictly from process.env.API_KEY as per instructions
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Removes watermarks from an image using the Gemini 2.5 Flash Image model.
 * 
 * @param base64Image The base64 encoded string of the image (without the data prefix).
 * @param mimeType The MIME type of the image.
 * @returns The base64 data of the processed image.
 */
export const removeWatermarkFromImage = async (
  base64Image: string,
  mimeType: string
): Promise<string> => {
  try {
    // Model selection: gemini-2.5-flash-image is the standard/free tier efficient image model.
    // It supports image editing via text prompts.
    const model = 'gemini-2.5-flash-image';

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image,
            },
          },
          {
            text: "Remove any watermarks, logos, or overlaid text from this image. Fill in the removed areas to match the surrounding background naturally. Return only the edited image.",
          },
        ],
      },
    });

    // Extract the image from the response
    // The response might contain text or other parts, we need to find the inlineData
    if (response.candidates && response.candidates.length > 0) {
      const parts = response.candidates[0].content.parts;
      for (const part of parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }

    throw new Error("No image data received from the model.");

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

