import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { UploadArea } from './components/UploadArea';
import { Button } from './components/ui/Button';
import { ComparisonView } from './components/ComparisonView';
import { removeWatermarkFromImage } from './services/geminiService';
import { LoadingState } from './types';

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<File | null>(null);
  const [originalPreviewUrl, setOriginalPreviewUrl] = useState<string | null>(null);
  const [processedImageUrl, setProcessedImageUrl] = useState<string | null>(null);
  const [loadingState, setLoadingState] = useState<LoadingState>({ status: 'idle' });

  // Cleanup object URLs to avoid memory leaks
  useEffect(() => {
    return () => {
      if (originalPreviewUrl) URL.revokeObjectURL(originalPreviewUrl);
    };
  }, [originalPreviewUrl]);

  const handleImageSelect = (file: File) => {
    setOriginalImage(file);
    const url = URL.createObjectURL(file);
    setOriginalPreviewUrl(url);

    // Reset state for new image
    setProcessedImageUrl(null);
    setLoadingState({ status: 'idle' });
  };

  const handleRemoveWatermark = async () => {
    if (!originalImage) return;

    setLoadingState({ status: 'processing', message: 'Analyzing image and removing artifacts...' });

    try {
      // Convert file to base64
      const reader = new FileReader();
      reader.readAsDataURL(originalImage);

      reader.onloadend = async () => {
        const base64String = reader.result as string;
        // Extract the actual base64 data (remove "data:image/xyz;base64,")
        const base64Data = base64String.split(',')[1];
        const mimeType = originalImage.type;

        try {
          const resultBase64 = await removeWatermarkFromImage(base64Data, mimeType);
          const resultUrl = `data:image/png;base64,${resultBase64}`;
          setProcessedImageUrl(resultUrl);
          setLoadingState({ status: 'success' });
        } catch (apiError) {
          console.error(apiError);
          setLoadingState({ 
            status: 'error', 
            message: 'Failed to process image. Please try again or use a smaller image.' 
          });
        }
      };

      reader.onerror = () => {
        setLoadingState({ status: 'error', message: 'Error reading file.' });
      };

    } catch (error) {
      console.error(error);
      setLoadingState({ status: 'error', message: 'An unexpected error occurred.' });
    }
  };

  const handleReset = () => {
    setOriginalImage(null);
    setOriginalPreviewUrl(null);
    setProcessedImageUrl(null);
    setLoadingState({ status: 'idle' });
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-8 md:py-12 flex flex-col items-center">

        <div className="w-full max-w-5xl space-y-8">

          {/* Hero Section */}
          {!originalImage && (
            <div className="text-center space-y-4 mb-12 animate-fade-in-up">
              <h2 className="text-4xl md:text-5xl font-bold text-white tracking-tight">
                Remove Watermarks <span className="text-blue-500">Instantly</span>
              </h2>
              <p className="text-lg text-slate-400 max-w-2xl mx-auto">
                Upload your image and let our AI restore the original background, removing text, logos, and watermarks seamlessly.
              </p>
            </div>
          )}

          {/* Upload Area */}
          {!originalImage && (
            <div className="max-w-2xl mx-auto w-full">
              <UploadArea onImageSelected={handleImageSelect} />
            </div>
          )}

          {/* Editor / Processing Area */}
          {originalImage && (
            <div className="w-full space-y-8 animate-fade-in">

              {/* Controls */}
              <div className="flex flex-col sm:flex-row items-center justify-between gap-4 p-4 bg-slate-900 rounded-xl border border-slate-800">
                <div className="flex items-center gap-3">
                    <span className="px-3 py-1 bg-slate-800 rounded-full text-xs font-medium text-slate-300">
                        {originalImage.name}
                    </span>
                    <span className="text-xs text-slate-500">
                        {(originalImage.size / 1024 / 1024).toFixed(2)} MB
                    </span>
                </div>
                <div className="flex gap-3 w-full sm:w-auto">
                  <Button variant="secondary" onClick={handleReset} disabled={loadingState.status === 'processing'}>
                    New Image
                  </Button>
                  {!processedImageUrl && (
                    <Button 
                      onClick={handleRemoveWatermark} 
                      isLoading={loadingState.status === 'processing'}
                      disabled={loadingState.status === 'processing'}
                      className="flex-1 sm:flex-none"
                    >
                      Remove Watermark
                    </Button>
                  )}
                </div>
              </div>

              {/* Error Message */}
              {loadingState.status === 'error' && (
                <div className="p-4 bg-red-900/20 border border-red-500/50 rounded-xl text-red-200 text-center">
                  <p>{loadingState.message || 'Something went wrong.'}</p>
                </div>
              )}

              {/* Main Display Area */}
              <div className="w-full">
                {!processedImageUrl ? (
                  // Single View (Before Processing)
                  <div className="flex flex-col items-center justify-center bg-slate-900/50 border border-slate-800 rounded-2xl p-4 md:p-8 min-h-[400px]">
                    {loadingState.status === 'processing' ? (
                        <div className="flex flex-col items-center gap-4">
                            <div className="relative w-24 h-24">
                                <div className="absolute inset-0 border-4 border-slate-700 rounded-full"></div>
                                <div className="absolute inset-0 border-4 border-blue-500 rounded-full border-t-transparent animate-spin"></div>
                            </div>
                            <h3 className="text-xl font-semibold text-white">Magic in progress...</h3>
                            <p className="text-slate-400">Removing unwanted elements from your image.</p>
                        </div>
                    ) : (
                        <img 
                            src={originalPreviewUrl!} 
                            alt="Original Preview" 
                            className="max-h-[600px] w-auto max-w-full rounded-lg shadow-2xl"
                        />
                    )}
                  </div>
                ) : (
                  // Comparison View (After Processing)
                  <ComparisonView 
                    originalUrl={originalPreviewUrl!} 
                    processedUrl={processedImageUrl} 
                  />
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="w-full py-6 border-t border-slate-800 bg-slate-900 text-center text-slate-500 text-sm">
        <p>© {new Date().getFullYear()} Watermark Remover AI. Designed for efficiency.</p>
      </footer>
    </div>
  );
};

export default App;

