import { GoogleGenAI } from "@google/genai";

// Initialize the client
// API Key is strictly from process.env.API_KEY as per instructions
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Removes watermarks from an image using the Gemini 2.5 Flash Image model.
 * 
 * @param base64Image The base64 encoded string of the image (without the data prefix).
 * @param mimeType The MIME type of the image.
 * @param instructions Optional user instructions for specific watermark locations.
 * @returns The base64 data of the processed image.
 */
export const removeWatermarkFromImage = async (
  base64Image: string,
  mimeType: string,
  instructions?: string
): Promise<string> => {
  try {
    // Model selection: gemini-2.5-flash-image is the standard/free tier efficient image model.
    // It supports image editing via text prompts.
    const model = 'gemini-2.5-flash-image';

    let prompt = "Remove any watermarks, logos, digital stamps, or overlaid text from this image. Fill in the removed areas to match the surrounding background texture and lighting naturally.";

    if (instructions && instructions.trim().length > 0) {
      prompt += ` Focus specifically on this area or detail: ${instructions}`;
    } else {
      prompt += " Pay special attention to the bottom-right corner and other edges where watermarks are commonly placed. If there is text that is clearly part of the scene (like a street sign), leave it, but remove overlay branding.";
    }

    prompt += " Return only the edited image.";

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image,
            },
          },
          {
            text: prompt,
          },
        ],
      },
    });

    // Extract the image from the response
    // The response might contain text or other parts, we need to find the inlineData
    if (response.candidates && response.candidates.length > 0) {
      const parts = response.candidates[0].content.parts;
      for (const part of parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }

    throw new Error("No image data received from the model.");

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

