                      <span className="text-xs text-slate-500">
                          {(originalImage.size / 1024 / 1024).toFixed(2)} MB
                      </span>
                  </div>
                  <Button variant="secondary" onClick={handleReset} disabled={loadingState.status === 'processing'}>
                    New Image
                  </Button>
                </div>

                {/* Processing Input */}
                {!processedImageUrl && (
                  <div className="flex flex-col md:flex-row gap-3 pt-2 border-t border-slate-800">
                    <div className="flex-grow relative group">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5 text-slate-500">
                              <path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09zM18.259 8.715L18 9.75l-.259-1.035a3.375 3.375 0 00-2.455-2.456L14.25 6l1.036-.259a3.375 3.375 0 002.455-2.456L18 2.25l.259 1.035a3.375 3.375 0 002.456 2.456L21.75 6l-1.035.259a3.375 3.375 0 00-2.456 2.456z" />
